import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../../repositories/providers.dart';
final usersProvider = StreamProvider((ref)=>ref.watch(adminRepositoryProvider).users());
class UsersScreen extends ConsumerWidget { const UsersScreen({super.key}); @override Widget build(BuildContext context, WidgetRef ref)=>Scaffold(appBar: AppBar(title: const Text('Kelola User')), body: ref.watch(usersProvider).when(data:(items)=>ListView(padding: const EdgeInsets.all(16), children: items.map((u)=>Card(child: ListTile(leading: CircleAvatar(child: Text(u.name.isEmpty?'U':u.name[0])), title: Text(u.name), subtitle: Text('${u.email} • ${u.role} • ${u.status}'), trailing: Wrap(children:[TextButton(onPressed:()=>ref.read(adminRepositoryProvider).setUserStatus(u.uid, 'active'), child: const Text('Aktifkan')), TextButton(onPressed:()=>ref.read(adminRepositoryProvider).setUserStatus(u.uid, 'disabled'), child: const Text('Nonaktifkan')), IconButton(onPressed:()=>ref.read(adminRepositoryProvider).deleteUserDoc(u.uid), icon: const Icon(Icons.delete_outline))]))).toList()), error:(e,_)=>Center(child:Text('$e')), loading:()=>const Center(child:CircularProgressIndicator()))); }
